/* Brainstorm panel */
.ws-brainstorm {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 16px;
  margin-bottom: 20px;
}

.ws-brainstorm h3 {
  margin: 0 0 12px 0;
  font-size: 1rem;
  color: var(--text);
}

.ws-brainstorm-row {
  display: flex;
  gap: 12px;
  align-items: center;
}

.ws-brainstorm-row select {
  padding: 8px 12px;
  border-radius: 4px;
  border: 1px solid var(--border);
  background: var(--bg);
  color: var(--text);
}

/* Tasks.md editor */
#ws-tasks-md-container {
  margin-top: 16px;
  border-top: 1px solid var(--border);
  padding-top: 16px;
}

.ws-tasks-md-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 8px;
}

#ws-tasks-md {
  width: 100%;
  min-height: 200px;
  max-height: 400px;
  font-family: var(--mono);
  font-size: 0.8rem;
  padding: 12px;
  border: 1px solid var(--border);
  border-radius: 4px;
  background: var(--bg);
  color: var(--text);
  resize: vertical;
}

.ws-tasks-md-actions {
  display: flex;
  gap: 8px;
  margin-top: 8px;
}

.ws-brainstorm.loading button {
  opacity: 0.6;
  pointer-events: none;
}
